ValidationRule.errorConditionFormula:
OR(
    AND(
								!SAP_Order__c,
        TEXT(Order_type__c)='ZAR2',
        OR(
            ISNULL(Invoice__c),
            ISBLANK(Invoice__c)
        )
    ),

    AND(
								!SAP_Order__c,
        TEXT(Order_type__c)!='ZAR2',
        NOT(
            OR(
                ISNULL(Invoice__c),
                ISBLANK(Invoice__c)
            )
        )
    )
)
